import React, { useEffect, useState, useRef, useCallback } from 'react';
import { useOS } from '../../store';
import { Mic, MicOff, Send, Zap, Loader2, Volume2, Square, AlertCircle, RefreshCw, Radio, Sparkles } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { 
  ExtractionPanel, 
  ExtractedField, 
  createDefaultFields, 
  extractFromTranscript, 
  calculateCompleteness 
} from './ExtractionPanel';

// --- AUDIO UTILS (PCM Handling) ---
const floatTo16BitPCM = (input: Float32Array) => {
    const output = new Int16Array(input.length);
    for (let i = 0; i < input.length; i++) {
        const s = Math.max(-1, Math.min(1, input[i]));
        output[i] = s < 0 ? s * 0x8000 : s * 0x7FFF;
    }
    return output;
};

const base64ToUint8Array = (base64: string) => {
    const binaryString = atob(base64);
    const bytes = new Uint8Array(binaryString.length);
    for (let i = 0; i < binaryString.length; i++) {
        bytes[i] = binaryString.charCodeAt(i);
    }
    return bytes;
};

// --- SYSTEM PROMPT FOR BETTER EXTRACTION ---
const PORTA_SYSTEM_PROMPT = `You are Porta, AEDIL's intelligent field service intake agent. Your goal is to have a natural, empathetic conversation while gathering critical information for a service ticket.

INFORMATION TO COLLECT:
1. Company name (who is calling)
2. Machine model and serial number
3. Error code (if displayed)
4. Symptom description (what's happening)
5. Environment details (indoor/outdoor, temperature if relevant)
6. Urgency level (is production stopped?)
7. Contact name and callback number

CONVERSATION STYLE:
- Be warm and professional, not robotic
- Acknowledge information naturally ("Got it, DMK Milch with an EJC 220...")
- Ask follow-up questions one at a time
- Express empathy for their situation
- Confirm critical details back to them
- Keep responses concise (1-2 sentences max)

If the caller is stressed about downtime, acknowledge it: "I understand every minute counts. Let me get this to our team right away."

Start by introducing yourself and asking how you can help.`;

export const Porta: React.FC = () => {
  const { porta, addPortaMessage, finalizePortaSession, setPortaStatus } = useOS();
  const [isConnected, setIsConnected] = useState(false);
  const [inputValue, setInputValue] = useState('');
  const [volume, setVolume] = useState(0);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [isRetrying, setIsRetrying] = useState(false);

  // EXTRACTION STATE
  const [extractedFields, setExtractedFields] = useState<ExtractedField[]>(createDefaultFields());
  const [completeness, setCompleteness] = useState(0);
  const [recentlyUpdatedIds, setRecentlyUpdatedIds] = useState<string[]>([]);
  const [isExtracting, setIsExtracting] = useState(false);
  const extractionBufferRef = useRef<string>('');

  // Refs for Audio Context & Session
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const volumeAnimationFrame = useRef<number>(0);
  const reconnectTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  // Transcription Accumulators
  const currentInputTranscription = useRef('');
  const currentOutputTranscription = useRef('');

  // Playback cursor
  const nextStartTimeRef = useRef<number>(0);

  // Scroll to bottom
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [porta.messages]);

  // CLEANUP ON UNMOUNT
  useEffect(() => {
    return () => {
      disconnectLiveSession(false);
    };
  }, []);

  // EXTRACTION PROCESSOR - Debounced to avoid over-processing
  const processExtraction = useCallback((newText: string) => {
    if (!newText.trim()) return;

    setIsExtracting(true);
    extractionBufferRef.current += ' ' + newText;

    // Extract from accumulated buffer for better context
    setExtractedFields(prevFields => {
      const previousValues = prevFields.map(f => ({ id: f.id, value: f.value }));
      const updated = extractFromTranscript(extractionBufferRef.current, prevFields);

      // Find newly updated fields for animation
      const newlyUpdated = updated
        .filter(f => {
          const prev = previousValues.find(p => p.id === f.id);
          return f.value && (!prev?.value || prev.value !== f.value);
        })
        .map(f => f.id);

      if (newlyUpdated.length > 0) {
        setRecentlyUpdatedIds(newlyUpdated);
        // Clear the "new" state after animation
        setTimeout(() => setRecentlyUpdatedIds([]), 1500);
      }

      // Update completeness
      const newCompleteness = calculateCompleteness(updated);
      setCompleteness(newCompleteness);

      return updated;
    });

    setTimeout(() => setIsExtracting(false), 300);
  }, []);

  // Flush pending text to the store so it's not lost
  const flushTranscripts = () => {
      let hasNewData = false;
      if (currentInputTranscription.current.trim()) {
          const userText = currentInputTranscription.current;
          addPortaMessage('user', userText);
          processExtraction(userText); // Extract from user speech
          currentInputTranscription.current = '';
          hasNewData = true;
      }
      if (currentOutputTranscription.current.trim()) {
          addPortaMessage('ai', currentOutputTranscription.current);
          currentOutputTranscription.current = '';
          hasNewData = true;
      }
      return hasNewData;
  };

  const disconnectLiveSession = (shouldFinalize = false) => {
     if (reconnectTimeoutRef.current) {
         clearTimeout(reconnectTimeoutRef.current);
         reconnectTimeoutRef.current = null;
     }

     if (volumeAnimationFrame.current) {
         cancelAnimationFrame(volumeAnimationFrame.current);
     }

     flushTranscripts();

     if (mediaStreamRef.current) {
        mediaStreamRef.current.getTracks().forEach(track => track.stop());
        mediaStreamRef.current = null;
     }

     if (processorRef.current) {
        processorRef.current.disconnect();
        processorRef.current.onaudioprocess = null;
        processorRef.current = null;
     }

     if (analyserRef.current) {
         analyserRef.current.disconnect();
         analyserRef.current = null;
     }

     if (audioContextRef.current && audioContextRef.current.state !== 'closed') {
        audioContextRef.current.suspend().then(() => audioContextRef.current?.close()).catch(() => {});
        audioContextRef.current = null;
     }
     if (inputAudioContextRef.current && inputAudioContextRef.current.state !== 'closed') {
        inputAudioContextRef.current.suspend().then(() => inputAudioContextRef.current?.close()).catch(() => {});
        inputAudioContextRef.current = null;
     }

     setIsConnected(false);
     setPortaStatus('idle');
     setVolume(0);
     nextStartTimeRef.current = 0;
     sessionPromiseRef.current = null;

     if (shouldFinalize) {
         setTimeout(() => {
             // Pass extracted data to finalize
             finalizePortaSession(extractedFields);
         }, 300);
     }
  };

  const handleEndCall = () => {
      disconnectLiveSession(true);
  };

  const connectLiveSession = async () => {
    setErrorMsg(null);
    setIsRetrying(false);

    // Reset extraction state for new call
    setExtractedFields(createDefaultFields());
    setCompleteness(0);
    extractionBufferRef.current = '';

    if (sessionPromiseRef.current) return;

    if (!process.env.API_KEY) {
        setErrorMsg('No API Key found.');
        addPortaMessage('system', 'Error: No API Key found for Live connection.');
        return;
    }

    try {
        setPortaStatus('listening');
        addPortaMessage('system', 'Initializing voice uplink...');

        const stream = await navigator.mediaDevices.getUserMedia({ 
            audio: { 
                channelCount: 1, 
                echoCancellation: true,
                noiseSuppression: true,
                autoGainControl: true,
                sampleRate: 16000
            } 
        });
        mediaStreamRef.current = stream;

        const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;

        const inputCtx = new AudioContextClass({ sampleRate: 16000 });
        inputAudioContextRef.current = inputCtx;

        const outputCtx = new AudioContextClass({ sampleRate: 24000 });
        audioContextRef.current = outputCtx;

        await inputCtx.resume();
        await outputCtx.resume();

        const source = inputCtx.createMediaStreamSource(stream);

        const analyser = inputCtx.createAnalyser();
        analyser.fftSize = 64; 
        analyser.smoothingTimeConstant = 0.5;
        analyserRef.current = analyser;

        const processor = inputCtx.createScriptProcessor(4096, 1, 1);
        processorRef.current = processor;

        source.connect(analyser);
        analyser.connect(processor);

        const muteNode = inputCtx.createGain();
        muteNode.gain.value = 0;
        processor.connect(muteNode);
        muteNode.connect(inputCtx.destination);

        const updateVolume = () => {
            if (!analyserRef.current) return;
            const dataArray = new Uint8Array(analyserRef.current.frequencyBinCount);
            analyserRef.current.getByteFrequencyData(dataArray);

            let sum = 0;
            for(let i=0; i < dataArray.length; i++) sum += dataArray[i];
            const avg = sum / dataArray.length;

            setVolume(avg);
            volumeAnimationFrame.current = requestAnimationFrame(updateVolume);
        };
        updateVolume();

        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const config = {
            model: 'gemini-2.5-flash-native-audio-preview-09-2025',
            config: {
                responseModalities: [Modality.AUDIO],
                speechConfig: {
                    voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } }
                },
                inputAudioTranscription: {}, 
                outputAudioTranscription: {},
                systemInstruction: PORTA_SYSTEM_PROMPT
            }
        };

        const sessionPromise = ai.live.connect({
            model: config.model,
            config: config.config,
            callbacks: {
                onopen: () => {
                    console.log("[Porta] Connected");
                    setIsConnected(true);
                    addPortaMessage('system', 'Voice uplink established. Speak naturally.');

                    processor.onaudioprocess = (e) => {
                        if (inputCtx.state === 'suspended') {
                            inputCtx.resume();
                        }

                        const inputData = e.inputBuffer.getChannelData(0);
                        const pcm16 = floatTo16BitPCM(inputData);

                        const uint8 = new Uint8Array(pcm16.buffer);
                        let binary = '';
                        const len = uint8.byteLength;
                        for (let i = 0; i < len; i++) binary += String.fromCharCode(uint8[i]);
                        const b64 = btoa(binary);

                        sessionPromise.then(session => {
                            session.sendRealtimeInput({
                                media: {
                                    mimeType: 'audio/pcm;rate=16000',
                                    data: b64
                                }
                            });
                        }).catch(() => {});
                    };
                },
                onmessage: async (msg: LiveServerMessage) => {
                    // Handle Transcription
                    if (msg.serverContent?.outputTranscription) {
                        currentOutputTranscription.current += msg.serverContent.outputTranscription.text;
                    } 
                    if (msg.serverContent?.inputTranscription) {
                        const newText = msg.serverContent.inputTranscription.text;
                        currentInputTranscription.current += newText;

                        // Real-time extraction as user speaks
                        processExtraction(newText);
                    }

                    if (msg.serverContent?.turnComplete) {
                        flushTranscripts();
                    }

                    // Handle Audio Output
                    const audioData = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                    if (audioData) {
                        setPortaStatus('speaking');

                        const pcmData = base64ToUint8Array(audioData);
                        const int16Array = new Int16Array(pcmData.buffer);
                        const float32Array = new Float32Array(int16Array.length);
                        for (let i = 0; i < int16Array.length; i++) {
                            float32Array[i] = int16Array[i] / 32768.0;
                        }

                        const buffer = outputCtx.createBuffer(1, float32Array.length, 24000);
                        buffer.getChannelData(0).set(float32Array);

                        const source = outputCtx.createBufferSource();
                        source.buffer = buffer;
                        source.connect(outputCtx.destination);

                        const currentTime = outputCtx.currentTime;
                        if (nextStartTimeRef.current < currentTime) {
                            nextStartTimeRef.current = currentTime;
                        }
                        source.start(nextStartTimeRef.current);
                        nextStartTimeRef.current += buffer.duration;

                        source.onended = () => {
                             if (outputCtx && outputCtx.currentTime >= nextStartTimeRef.current - 0.2) {
                                 setPortaStatus('listening');
                             }
                        };
                    }

                    if (msg.serverContent?.interrupted) {
                        console.log("[Porta] Interrupted");
                        nextStartTimeRef.current = 0;
                        setPortaStatus('listening');
                        flushTranscripts();
                    }
                },
                onclose: () => {
                    console.log("[Porta] Session Closed");
                    setIsConnected(false);
                    setPortaStatus('idle');
                    addPortaMessage('system', 'Connection closed.');
                    sessionPromiseRef.current = null;
                },
                onerror: (err) => {
                    console.error("[Porta] Error", err);
                    const msg = (err as any)?.message || "Connection Error";
                    setErrorMsg(msg);
                    addPortaMessage('system', `Connection disrupted: ${msg}`);
                    setIsConnected(false);
                    setPortaStatus('idle');
                    sessionPromiseRef.current = null;
                }
            }
        });

        sessionPromiseRef.current = sessionPromise;

        sessionPromise.catch(e => {
            console.error("[Porta] Connection Initialization Failed", e);
            setErrorMsg("Service Unavailable");
            addPortaMessage('system', 'Service unavailable. Retrying in 2s...');
            setIsConnected(false);
            setPortaStatus('idle');
            sessionPromiseRef.current = null;

            if (!isRetrying) {
                setIsRetrying(true);
                reconnectTimeoutRef.current = setTimeout(() => {
                    connectLiveSession();
                }, 2000);
            }
        });

    } catch (e) {
        console.error("Setup Failed", e);
        setErrorMsg('Setup Failed');
        addPortaMessage('system', 'Failed to initialize audio subsystem.');
        setIsConnected(false);
        setPortaStatus('idle');
        sessionPromiseRef.current = null;
    }
  };

  const handleSendText = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputValue.trim()) return;

    // Process text input for extraction too
    processExtraction(inputValue);
    addPortaMessage('user', inputValue);

    if (sessionPromiseRef.current && isConnected) {
         sessionPromiseRef.current.then(session => {
            session.sendRealtimeInput({
                 media: {
                     mimeType: 'text/plain',
                     data: btoa(inputValue)
                 }
            });
         });
    }
    setInputValue('');
  };

  // Calculate filled required fields for quick stats
  const filledRequired = extractedFields.filter(f => f.required && f.value && f.confidence > 50).length;
  const totalRequired = extractedFields.filter(f => f.required).length;

  return (
    <div className="h-full bg-[#0B0C15] text-white flex font-sans overflow-hidden relative">

      {/* LEFT SIDE: VOICE INTERFACE */}
      <div className="flex-1 flex flex-col relative">
        {/* Background Ambience */}
        <div className="absolute inset-0 bg-gradient-to-b from-[#0F0F12] to-black pointer-events-none"></div>

        {/* Ambient glow based on status */}
        <div className={`absolute inset-0 transition-opacity duration-1000 pointer-events-none ${
          porta.status === 'speaking' ? 'opacity-100' : 'opacity-0'
        }`}>
          <div className="absolute top-1/3 left-1/2 -translate-x-1/2 w-96 h-96 bg-indigo-500/10 rounded-full blur-[100px]" />
        </div>
        <div className={`absolute inset-0 transition-opacity duration-1000 pointer-events-none ${
          porta.status === 'listening' && isConnected ? 'opacity-100' : 'opacity-0'
        }`}>
          <div className="absolute top-1/3 left-1/2 -translate-x-1/2 w-96 h-96 bg-emerald-500/10 rounded-full blur-[100px]" />
        </div>

        {/* Header */}
        <div className="h-16 flex items-center justify-between px-6 z-10 border-b border-white/5 bg-black/40 backdrop-blur-sm">
           <div className="flex items-center gap-3">
               <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-amber-500 to-amber-600 flex items-center justify-center shadow-lg shadow-amber-500/30">
                   <Zap className="w-5 h-5 text-black fill-black" />
               </div>
               <div>
                   <div className="font-bold text-sm tracking-wide text-white flex items-center gap-2">
                     AEDIL Porta
                     {isConnected && (
                       <span className="flex items-center gap-1 text-[9px] text-emerald-400 bg-emerald-500/10 px-2 py-0.5 rounded-full border border-emerald-500/20">
                         <span className="w-1.5 h-1.5 rounded-full bg-emerald-400 animate-pulse" />
                         LIVE
                       </span>
                     )}
                   </div>
                   <div className="text-[10px] text-slate-500 font-mono uppercase tracking-wider">Intelligent Voice Intake</div>
               </div>
           </div>

           {/* Quick Stats */}
           {isConnected && (
             <div className="flex items-center gap-4">
               <div className="text-right">
                 <div className="text-[10px] text-slate-500 uppercase tracking-wider">Fields Captured</div>
                 <div className="text-sm font-bold text-white">{filledRequired}/{totalRequired} Required</div>
               </div>
               <button 
                   onClick={() => finalizePortaSession(extractedFields)}
                   disabled={completeness < 50}
                   className={`px-4 py-2 rounded-lg text-xs font-bold border transition-all ${
                     completeness >= 80 
                       ? 'bg-emerald-600 hover:bg-emerald-500 text-white border-emerald-500 shadow-lg shadow-emerald-500/20' 
                       : completeness >= 50
                         ? 'bg-amber-600 hover:bg-amber-500 text-white border-amber-500'
                         : 'bg-white/5 text-slate-500 border-white/10 cursor-not-allowed'
                   }`}
               >
                   Create Ticket
               </button>
             </div>
           )}
        </div>

        {/* Main Visualizer Area */}
        <div className="flex-1 flex flex-col items-center justify-center relative z-0 px-8">

            {/* Central Orb */}
            <div className="relative mb-8">
               {/* Glow Layer */}
               <div 
                  className={`absolute inset-0 rounded-full blur-[80px] transition-all duration-300 ${
                      porta.status === 'listening' && isConnected ? 'bg-emerald-500/30' : 
                      porta.status === 'speaking' ? 'bg-indigo-500/40' : 'bg-white/5'
                  }`}
                  style={{ transform: `scale(${1.5 + (volume/40)})` }}
               ></div>

               {/* Waveform Ring */}
               {isConnected && (
                 <motion.div 
                   className="absolute inset-[-20px] rounded-full border-2 border-white/10"
                   animate={{ 
                     scale: [1, 1.1 + (volume/200), 1],
                     opacity: [0.3, 0.6, 0.3]
                   }}
                   transition={{ duration: 1.5, repeat: Infinity, ease: "easeInOut" }}
                 />
               )}

               {/* Button Wrapper */}
               <div className="relative flex items-center justify-center">
                   <button 
                       onClick={isConnected ? handleEndCall : connectLiveSession}
                       style={{ transform: `scale(${1 + (volume/250)})` }}
                       className={`w-36 h-36 rounded-full border-[3px] transition-all duration-300 flex items-center justify-center backdrop-blur-sm cursor-pointer z-10 ${
                       isConnected 
                          ? (porta.status === 'speaking' 
                              ? 'border-indigo-400/60 bg-indigo-500/10 shadow-[0_0_60px_rgba(99,102,241,0.3)]' 
                              : 'border-emerald-500/60 bg-emerald-500/10 shadow-[0_0_60px_rgba(16,185,129,0.3)]')
                          : 'border-white/10 bg-white/5 hover:border-amber-500/50 hover:bg-amber-500/5 hover:shadow-[0_0_40px_rgba(245,158,11,0.2)]'
                   }`}>
                       {porta.status === 'processing' ? (
                           <Loader2 className="w-14 h-14 text-white animate-spin" />
                       ) : isConnected ? (
                           porta.status === 'speaking' ? (
                               <div className="flex flex-col items-center gap-2">
                                 <Volume2 className="w-12 h-12 text-indigo-400" />
                                 <span className="text-[9px] text-indigo-300 font-bold uppercase tracking-wider">Speaking</span>
                               </div>
                           ) : (
                               <div className="flex flex-col items-center gap-2">
                                 {/* Visualizer Bars */}
                                 <div className="flex gap-1 items-end h-10">
                                     <motion.div 
                                       animate={{ height: [10, Math.max(15, volume/2), 10] }}
                                       transition={{ duration: 0.3, repeat: Infinity }}
                                       className="w-2 bg-emerald-500 rounded-full"
                                     />
                                     <motion.div 
                                       animate={{ height: [15, Math.max(25, volume/1.5), 15] }}
                                       transition={{ duration: 0.4, repeat: Infinity }}
                                       className="w-2 bg-emerald-400 rounded-full"
                                     />
                                     <motion.div 
                                       animate={{ height: [12, Math.max(20, volume/1.8), 12] }}
                                       transition={{ duration: 0.35, repeat: Infinity }}
                                       className="w-2 bg-emerald-500 rounded-full"
                                     />
                                 </div>
                                 <span className="text-[9px] text-emerald-300 font-bold uppercase tracking-wider">Listening</span>
                               </div>
                           )
                       ) : (
                           <div className="flex flex-col items-center gap-3">
                              <MicOff className="w-12 h-12 text-zinc-500" />
                              <span className="text-[10px] uppercase tracking-widest font-bold text-zinc-500">Tap to Start</span>
                           </div>
                       )}
                   </button>
               </div>
            </div>

            {/* Status Text */}
            <div className="text-center space-y-2 max-w-md px-6 min-h-[60px]">
                <h2 className="text-2xl font-light tracking-tight transition-all text-white">
                    {isConnected 
                      ? (porta.status === 'speaking' ? "Porta is responding..." : "Listening to caller...")
                      : "Ready for Intake"}
                </h2>
                <p className="text-slate-500 text-sm flex items-center justify-center gap-2">
                   {errorMsg ? (
                       <span className="text-red-400 flex items-center gap-1"><AlertCircle className="w-3 h-3" /> {errorMsg}</span>
                   ) : (
                       isConnected 
                         ? <span className="flex items-center gap-2"><Radio className="w-3 h-3 text-emerald-400" /> Live audio uplink active</span>
                         : "Click the orb to begin voice intake session"
                   )}
                </p>
            </div>
        </div>

        {/* Chat History */}
        <div className="h-44 px-6 pb-4 overflow-y-auto mask-fade-top space-y-3 z-10 relative">
            <AnimatePresence>
              {porta.messages.map((msg) => (
                  <motion.div 
                    key={msg.id}
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    className={`flex ${msg.sender === 'user' ? 'justify-end' : 'justify-start'}`}
                  >
                      <div className={`max-w-[85%] px-4 py-2.5 rounded-2xl text-xs leading-relaxed border ${
                          msg.sender === 'user' 
                            ? 'bg-[#1C1C1E] text-white border-white/10 rounded-tr-sm' 
                            : msg.sender === 'system' 
                              ? 'bg-transparent text-slate-500 border-transparent text-center w-full italic' 
                              : 'bg-indigo-500/10 text-indigo-200 border-indigo-500/20 rounded-tl-sm'
                      }`}>
                          {msg.text}
                      </div>
                  </motion.div>
              ))}
            </AnimatePresence>
            <div ref={messagesEndRef} />
        </div>

        {/* Controls */}
        <div className="h-20 bg-[#0A0A0A] border-t border-white/10 flex items-center px-6 gap-4 z-20">
            <button 
                onClick={isConnected ? handleEndCall : connectLiveSession}
                className={`w-12 h-12 rounded-full flex items-center justify-center transition-all shrink-0 ${
                    isConnected 
                      ? 'bg-red-500/20 text-red-500 border border-red-500/50 hover:bg-red-500 hover:text-white' 
                      : 'bg-amber-500/20 hover:bg-amber-500/30 text-amber-500 border border-amber-500/50'
                }`}
                title={isConnected ? "End Call" : "Start Call"}
            >
                {isConnected ? <Square className="w-4 h-4 fill-current" /> : <Mic className="w-5 h-5" />}
            </button>

            <form onSubmit={handleSendText} className="flex-1 relative">
                <input 
                    type="text" 
                    value={inputValue}
                    onChange={(e) => setInputValue(e.target.value)}
                    placeholder={isConnected ? "Type to send message..." : "Connect to start..."}
                    disabled={!isConnected}
                    className="w-full h-12 bg-[#1C1C1E] border border-white/10 rounded-full px-5 pr-12 text-sm text-white focus:outline-none focus:border-amber-500/50 transition-colors disabled:opacity-50 placeholder:text-zinc-600"
                />
                <button 
                    type="submit"
                    disabled={!inputValue.trim() || !isConnected}
                    className="absolute right-2 top-2 bottom-2 w-8 h-8 bg-amber-600 rounded-full flex items-center justify-center disabled:opacity-30 disabled:bg-white/10 transition-colors hover:bg-amber-500 text-white"
                >
                    <Send className="w-4 h-4" />
                </button>
            </form>
        </div>
      </div>

      {/* RIGHT SIDE: EXTRACTION PANEL */}
      <AnimatePresence>
        {(isConnected || completeness > 0) && (
          <ExtractionPanel
            fields={extractedFields}
            completeness={completeness}
            isExtracting={isExtracting}
            isConnected={isConnected}
            recentlyUpdatedIds={recentlyUpdatedIds}
          />
        )}
      </AnimatePresence>

    </div>
  );
};

export default Porta;
